import {useEffect,useState} from 'react';export default function MovieSuggestions(){const[m,setM]=useState([]);const[l,setL]=useState(true);useEffect(()=>{fetch('https://jsonplaceholder.typicode.com/users').then(r=>r.json()).then(d=>{setM(d);setL(false)}).catch(()=>setL(false));},[]);return <div className='card p-3'><h4>Movie Suggestions</h4>{l?<p>Loading...</p>:<ul>{m.map(x=><li key={x.id}>{x.name}</li>)}</ul>}</div>}